def execute(params):
    """Search for regex patterns in text."""
    import re

    text = params.get('text')
    pattern = params.get('pattern')

    if not text or not pattern:
        return {'success': False, 'error': 'text and pattern parameters are required'}

    flags_str = params.get('flags', '')
    flags = 0
    if 'i' in flags_str:
        flags |= re.IGNORECASE
    if 'm' in flags_str:
        flags |= re.MULTILINE
    if 's' in flags_str:
        flags |= re.DOTALL

    try:
        matches = re.finditer(pattern, text, flags)
        results = []
        for match in matches:
            results.append({
                'match': match.group(),
                'start': match.start(),
                'end': match.end(),
                'groups': match.groups()
            })

        return {
            'success': True,
            'count': len(results),
            'matches': results
        }
    except re.error as e:
        return {'success': False, 'error': f'Invalid regex pattern: {str(e)}'}

